mapper.select:
select c.contract_id, c.contract_code, c.contract_name, c.customer_id, c.dept_id, c.contract_type, c.contract_status, c.contract_sign_date, c.contract_period, c.contract_amount, c.tax_rate, c.amount_no_tax, c.tax_amount, c.confirm_amount, c.confirm_year, c.free_maintenance_period, c.create_by, c.create_time, c.update_by, c.update_time, c.remark, d.dept_name as dept_name, cust.customer_simple_name as customer_name, dict1.dict_label as contract_type_name, dict2.dict_label as contract_status_name, u1.nick_name as create_by_name, u2.nick_name as update_by_name, IFNULL(p_agg.project_budget_total, 0) AS project_budget_total, IFNULL(p_agg.estimated_workload_total, 0) AS estimated_workload_total, IFNULL(p_agg.actual_workload_total, 0) AS actual_workload_total, IFNULL(p_agg.revenue_confirm_amount_total, 0) AS revenue_confirm_amount_total from pm_contract c left join sys_dept d on c.dept_id = d.dept_id left join pm_customer cust on c.customer_id = cust.customer_id left join sys_dict_data dict1 on c.contract_type COLLATE utf8mb4_unicode_ci = dict1.dict_value and dict1.dict_type = 'sys_htlx' left join sys_dict_data dict2 on c.contract_status COLLATE utf8mb4_unicode_ci = dict2.dict_value and dict2.dict_type = 'sys_htzt' left join sys_user u1 on c.create_by = u1.user_name COLLATE utf8mb4_0900_ai_ci left join sys_user u2 on c.update_by = u2.user_name COLLATE utf8mb4_0900_ai_ci left join ( select rel.contract_id, IFNULL(SUM(p.project_budget), 0) AS project_budget_total, IFNULL(SUM(p.estimated_workload), 0) AS estimated_workload_total, IFNULL(SUM(ROUND(p.actual_workload / 8, 3) + COALESCE(p.adjust_workload, 0)), 0) AS actual_workload_total, IFNULL(SUM(p.confirm_amount), 0) AS revenue_confirm_amount_total from pm_project p inner join pm_project_contract_rel rel on p.project_id = rel.project_id and rel.del_flag = '0' where p.del_flag = '0' group by rel.contract_id ) p_agg on c.contract_id = p_agg.contract_id
c.del_flag = '0' and c.contract_code like concat('%', #{contractCode}, '%') and c.contract_name like concat('%', #{contractName}, '%') and c.customer_id = #{customerId}
and (c.dept_id = #{deptId} or c.dept_id in (select dept_id from sys_dept where find_in_set(#{deptId}, ancestors) > 0))
and c.contract_type = #{contractType} and c.contract_status = #{contractStatus}
and c.contract_id in ( select rel2.contract_id from pm_project_contract_rel rel2 inner join pm_project p2 on rel2.project_id = p2.project_id and p2.del_flag = '0' where rel2.del_flag = '0' and p2.revenue_confirm_year = #{confirmYear} )
${params.dataScope}
order by c.update_time desc

mapper.update:
update pm_contract
contract_code = #{contractCode}, contract_name = #{contractName}, customer_id = #{customerId}, dept_id = #{deptId}, contract_type = #{contractType}, contract_status = #{contractStatus}, contract_sign_date = #{contractSignDate}, contract_period = #{contractPeriod}, contract_amount = #{contractAmount}, tax_rate = #{taxRate}, amount_no_tax = #{amountNoTax}, tax_amount = #{taxAmount}, confirm_amount = #{confirmAmount}, confirm_year = #{confirmYear}, free_maintenance_period = #{freeMaintenancePeriod}, del_flag = #{delFlag}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark}, reserved_field1 = #{reservedField1}, reserved_field2 = #{reservedField2}, reserved_field3 = #{reservedField3}, reserved_field4 = #{reservedField4}, reserved_field5 = #{reservedField5},
where contract_id = #{contractId}

mapper.select:
select COALESCE(sum(p.payment_amount), 0)
from pm_contract c
left join pm_customer cust on c.customer_id = cust.customer_id
left join pm_payment p on c.contract_id = p.contract_id and p.del_flag = '0'

    c.del_flag = '0'
     and c.contract_code like concat('%', #{contractCode}, '%')
     and c.contract_name like concat('%', #{contractName}, '%')
     and c.customer_id = #{customerId}
     and cust.customer_simple_name like concat('%', #{customerName}, '%')

        and (c.dept_id = #{deptId}
             or c.dept_id in (select dept_id from sys_dept where find_in_set(#{deptId}, ancestors) > 0))


        and (c.dept_id in #{id}
            or c.dept_id in (select dept_id from sys_dept where find_in_set(#{id}, ancestors) > 0))

     and c.contract_type = #{contractType}
     and c.contract_status = #{contractStatus}
     and p.confirm_year = #{confirmYear}
     and p.payment_method_name like concat('%', #{params.paymentMethodName}, '%')
     and p.has_penalty = #{params.hasPenalty}
     and p.payment_status = #{params.paymentStatus}
     and p.payment_status in #{s}
     and p.expected_quarter = #{expectedQuarter}
     and p.expected_quarter in #{s}
     and p.actual_quarter = #{params.actualQuarter}
     and p.actual_quarter in #{s}
     and p.actual_payment_date >= #{params.actualPaymentDateStart}
     and p.actual_payment_date <= #{params.actualPaymentDateEnd}

SELECT contract_id AS contractId, contract_code AS contractCode, contract_name AS contractName, contract_status AS contractStatus, contract_amount AS contractAmount FROM pm_contract WHERE del_flag = '0' AND dept_id = #{deptId}
AND (contract_name LIKE CONCAT('%', #{keyword}, '%') OR contract_code LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY create_time DESC LIMIT 100
